import React, { useState, useRef } from 'react';
import {
  FaLayerGroup, FaArrowLeft, FaArrowRight, FaUpload,
  FaFilePdf, FaTrash, FaLinkedin, FaGithub, FaCode,
  FaBriefcase, FaPalette, FaTimesCircle, FaAward,
} from 'react-icons/fa';
import './ApplicationForm.css';

const DOMAINS = [
  {
    key: 'tech',
    name: 'Tech',
    icon: <FaCode />,
    color: '#7C5AED',
    bg: 'rgba(124,90,237,0.08)',
    border: 'rgba(124,90,237,0.25)',
    subDomains: ['Web / App Dev', 'AI & ML', 'Cloud & DevOps'],
  },
  {
    key: 'corp',
    name: 'Corp',
    icon: <FaBriefcase />,
    color: '#4361ee',
    bg: 'rgba(67,97,238,0.08)',
    border: 'rgba(67,97,238,0.25)',
    subDomains: ['Events', 'Personal Relations', 'HR & Admin', 'Sponsorship'],
  },
  {
    key: 'creatives',
    name: 'Creatives',
    icon: <FaPalette />,
    color: '#f77f00',
    bg: 'rgba(247,127,0,0.08)',
    border: 'rgba(247,127,0,0.25)',
    subDomains: ['Digital Design', 'Media', 'UI/UX'],
  },
];

function validate(data) {
  const errs = {};
  if (!data.certs || data.certs.length === 0)
    errs.certs = 'Please upload at least one AWS certificate (min 1, max 3)';
  if (!data.domain)
    errs.domain = 'Please select a domain';
  if (!data.subDomains || data.subDomains.length === 0)
    errs.subDomains = 'Please select at least one sub-domain';
  if (!data.resume)
    errs.resume = 'Resume is mandatory';
  if (!data.linkedin || !/^https?:\/\/(www\.)?linkedin\.com\/.+/.test(data.linkedin))
    errs.linkedin = 'Please enter a valid LinkedIn profile URL';
  if (!data.github || !/^https?:\/\/(www\.)?github\.com\/.+/.test(data.github))
    errs.github = 'Please enter a valid GitHub profile URL';
  return errs;
}

function FileUploadBox({ label, sublabel, accept, maxFiles, files, onAdd, onRemove, error }) {
  const inputRef = useRef();

  function handleDrop(e) {
    e.preventDefault();
    const dropped = Array.from(e.dataTransfer.files);
    handleFiles(dropped);
  }

  function handleFiles(newFiles) {
    const remaining = maxFiles - files.length;
    const toAdd = newFiles.slice(0, remaining);
    onAdd(toAdd);
  }

  return (
    <div className="af-field-group">
      <label className="af-label">
        {label} <span className="req">*</span>
        {sublabel && (
          <span style={{ color: '#aaa', fontWeight: 400, marginLeft: 8 }}>{sublabel}</span>
        )}
      </label>

      {/* Drop zone */}
      {files.length < maxFiles && (
        <div
          onDragOver={e => e.preventDefault()}
          onDrop={handleDrop}
          onClick={() => inputRef.current.click()}
          style={{
            border: `2px dashed ${error ? '#e53e3e' : 'rgba(124,90,237,0.3)'}`,
            borderRadius: 12,
            padding: '28px 20px',
            textAlign: 'center',
            cursor: 'pointer',
            background: error ? 'rgba(229,62,62,0.02)' : 'rgba(124,90,237,0.02)',
            transition: 'all 0.2s',
          }}
        >
          <FaUpload style={{ fontSize: 24, color: error ? '#e53e3e' : '#7C5AED', marginBottom: 8 }} />
          <p style={{ fontFamily: 'Share Tech, sans-serif', fontSize: 14, color: error ? '#e53e3e' : '#7C5AED', margin: 0 }}>
            Click to upload {label.toLowerCase()}
          </p>
          <p style={{ fontFamily: 'Raleway, sans-serif', fontSize: 12, color: '#aaa', marginTop: 4 }}>
            {accept.toUpperCase().replace(/\./g, '').replace(/,/g, ', ')} — {sublabel}
          </p>
          <input
            ref={inputRef}
            type="file"
            accept={accept}
            multiple={maxFiles > 1}
            style={{ display: 'none' }}
            onChange={e => handleFiles(Array.from(e.target.files))}
          />
        </div>
      )}

      {/* Uploaded files list */}
      {files.length > 0 && (
        <div style={{ marginTop: 10, display: 'flex', flexDirection: 'column', gap: 8 }}>
          {files.map((f, i) => (
            <div
              key={i}
              style={{
                display: 'flex', alignItems: 'center', gap: 10,
                background: 'rgba(124,90,237,0.04)', border: '1px solid rgba(124,90,237,0.15)',
                borderRadius: 8, padding: '8px 12px',
              }}
            >
              <FaFilePdf style={{ color: '#7C5AED', fontSize: 16 }} />
              <span style={{ fontFamily: 'Raleway, sans-serif', fontSize: 13, color: '#333', flex: 1, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                {f.name}
              </span>
              <span style={{ fontFamily: 'Raleway, sans-serif', fontSize: 11, color: '#aaa' }}>
                {(f.size / 1024 / 1024).toFixed(1)} MB
              </span>
              <FaTrash
                style={{ color: '#e53e3e', cursor: 'pointer', fontSize: 13 }}
                onClick={() => onRemove(i)}
              />
            </div>
          ))}
        </div>
      )}

      {error && <p className="field-error"><span>•</span>{error}</p>}
    </div>
  );
}

export default function Step2DocsAndDomains({ data, onChange, onPrev, onNext }) {
  const [errors, setErrors] = useState({});

  function update(field, val) {
    onChange({ ...data, [field]: val });
  }

  function addCerts(newFiles) {
    const combined = [...data.certs, ...newFiles].slice(0, 3);
    update('certs', combined);
  }

  function removeCert(idx) {
    update('certs', data.certs.filter((_, i) => i !== idx));
  }

  function selectDomain(key) {
    onChange({ ...data, domain: key, subDomains: [] });
  }

  function toggleSubDomain(sub) {
    const current = data.subDomains;
    const next = current.includes(sub)
      ? current.filter(s => s !== sub)
      : [...current, sub];
    update('subDomains', next);
  }

  function handleNext() {
    const errs = validate(data);
    if (Object.keys(errs).length > 0) {
      setErrors(errs);
      return;
    }
    onNext();
  }

  const selectedDomain = DOMAINS.find(d => d.key === data.domain);
  const e = errors;

  return (
    <div className="af-form-card">
      <div className="af-card-header">
        <div className="af-card-icon"><FaLayerGroup /></div>
        <div>
          <h2 className="af-card-title">Domain Preferences &amp; Documents</h2>
          <p className="af-card-subtitle">Choose your preferred domains and upload documents</p>
        </div>
      </div>

      {/* AWS Certificates */}
      <FileUploadBox
        label="AWS Certificate(s)"
        sublabel="Min 1, Max 3 — PDF / PNG / JPG, up to 5 MB each"
        accept=".pdf,.png,.jpg,.jpeg"
        maxFiles={3}
        files={data.certs}
        onAdd={addCerts}
        onRemove={removeCert}
        error={e.certs}
      />

      {/* Domain selection */}
      <div className="af-field-group">
        <label className="af-label">
          Domain Preference <span className="req">*</span>
        </label>
        <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap' }}>
          {DOMAINS.map(d => (
            <div
              key={d.key}
              onClick={() => selectDomain(d.key)}
              style={{
                flex: '1 1 160px', minWidth: 140, padding: '18px 16px',
                borderRadius: 12, cursor: 'pointer', textAlign: 'center',
                border: `2px solid ${data.domain === d.key ? d.color : '#dde2f0'}`,
                background: data.domain === d.key ? d.bg : '#fff',
                transition: 'all 0.2s',
              }}
            >
              <div style={{ fontSize: 22, color: data.domain === d.key ? d.color : '#ccc', marginBottom: 8 }}>
                {d.icon}
              </div>
              <p style={{
                fontFamily: 'Sarpanch, sans-serif', fontSize: 14, fontWeight: 700,
                color: data.domain === d.key ? d.color : '#333', margin: 0,
              }}>
                {d.name}
              </p>
            </div>
          ))}
        </div>
        {e.domain && <p className="field-error"><span>•</span>{e.domain}</p>}
      </div>

      {/* Sub-domain selection */}
      {selectedDomain && (
        <div className="af-field-group">
          <label className="af-label">
            Sub-Domain <span className="req">*</span>
            <span style={{ color: '#aaa', fontWeight: 400, marginLeft: 8 }}>You can select multiple</span>
          </label>
          <div style={{ display: 'flex', flexWrap: 'wrap', gap: 10 }}>
            {selectedDomain.subDomains.map(sub => {
              const isActive = data.subDomains.includes(sub);
              return (
                <div
                  key={sub}
                  onClick={() => toggleSubDomain(sub)}
                  style={{
                    padding: '10px 18px', borderRadius: 8, cursor: 'pointer',
                    border: `1.5px solid ${isActive ? selectedDomain.color : '#dde2f0'}`,
                    background: isActive ? selectedDomain.bg : '#fff',
                    fontFamily: 'Share Tech, sans-serif', fontSize: 13,
                    color: isActive ? selectedDomain.color : '#555',
                    transition: 'all 0.2s',
                    display: 'flex', alignItems: 'center', gap: 6,
                  }}
                >
                  {isActive && <FaAward style={{ fontSize: 11 }} />}
                  {sub}
                </div>
              );
            })}
          </div>
          {e.subDomains && <p className="field-error"><span>•</span>{e.subDomains}</p>}
        </div>
      )}

      {/* Resume */}
      <FileUploadBox
        label="Resume / CV"
        sublabel="PDF, DOC, DOCX — up to 10 MB"
        accept=".pdf,.doc,.docx"
        maxFiles={1}
        files={data.resume ? [data.resume] : []}
        onAdd={files => update('resume', files[0])}
        onRemove={() => update('resume', null)}
        error={e.resume}
      />

      {/* LinkedIn */}
      <div className="af-field-group">
        <label className="af-label">LinkedIn Profile <span className="req">*</span></label>
        <div className="af-input-wrap">
          <span className="af-input-icon"><FaLinkedin /></span>
          <input
            className={`af-input ${e.linkedin ? 'has-error' : ''}`}
            type="url"
            placeholder="https://linkedin.com/in/your-profile"
            value={data.linkedin}
            onChange={ev => update('linkedin', ev.target.value)}
          />
        </div>
        {e.linkedin && <p className="field-error"><span>•</span>{e.linkedin}</p>}
      </div>

      {/* GitHub */}
      <div className="af-field-group">
        <label className="af-label">GitHub Profile <span className="req">*</span></label>
        <div className="af-input-wrap">
          <span className="af-input-icon"><FaGithub /></span>
          <input
            className={`af-input ${e.github ? 'has-error' : ''}`}
            type="url"
            placeholder="https://github.com/your-username"
            value={data.github}
            onChange={ev => update('github', ev.target.value)}
          />
        </div>
        {e.github && <p className="field-error"><span>•</span>{e.github}</p>}
      </div>

      {/* Navigation */}
      <div className="af-nav-buttons">
        <button className="af-btn-prev" onClick={onPrev}>
          <FaArrowLeft /> Previous
        </button>
        <button className="af-btn-next" onClick={handleNext}>
          Next Step <FaArrowRight />
        </button>
      </div>
    </div>
  );
}
